mapper.insert:
insert into batch.batch_day_replay_entry (
    session_id, tenant_id, job_code, source_instance_id, rerun_instance_id,
    status, failure_reason, started_at, finished_at, result_version_id,
    created_at, updated_at
) values (
    #{sessionId}, #{tenantId}, #{jobCode}, #{sourceInstanceId}, #{rerunInstanceId},
    #{status}, #{failureReason}, #{startedAt}, #{finishedAt}, #{resultVersionId},
    #{createdAt}, #{updatedAt}
)
on conflict (session_id, tenant_id, job_code) do nothing

mapper.select:
select * from batch.batch_day_replay_entry
where session_id = #{sessionId}
order by id asc

select * from batch.batch_day_replay_entry
where session_id = #{sessionId} and status = #{status}
order by id asc
limit #{limit}

select * from batch.batch_day_replay_entry
where tenant_id = #{tenantId} and rerun_instance_id = #{rerunInstanceId}
limit 1

select * from batch.batch_day_replay_entry
where session_id = #{sessionId}
  and tenant_id = #{tenantId}
  and source_instance_id = #{sourceInstanceId}
limit 1

mapper.update:
update batch.batch_day_replay_entry
set status            = #{toStatus},
    rerun_instance_id = coalesce(#{rerunInstanceId}, rerun_instance_id),
    result_version_id = coalesce(#{resultVersionId}, result_version_id),
    failure_reason    = coalesce(#{failureReason}, failure_reason),
    started_at        = coalesce(#{startedAt}, started_at),
    finished_at       = coalesce(#{finishedAt}, finished_at),
    updated_at        = #{now}
where tenant_id = #{tenantId}
  and id = #{id}
